function TechPill({ label }: { label: string }) {
  return (
    <span className="px-2.5 py-1 text-[10px] font-semibold uppercase tracking-wider bg-card/50 border border-border rounded-lg text-foreground/45">
      {label}
    </span>
  );
}

function ActionBtn({
  href,
  icon: Icon,
  label,
  filled = false,
  sm = false,
}: {
  href: string;
  icon: React.ElementType;
  label: string;
  filled?: boolean;
  sm?: boolean;
}) {
  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className={`inline-flex items-center gap-1.5 font-semibold transition-all duration-200 active:scale-95
        ${sm ? "px-3.5 py-2 text-[11px] rounded-xl" : "px-5 py-2.5 text-xs rounded-xl"}
        ${
          filled
            ? "bg-foreground text-background hover:bg-foreground/90 shadow-lg shadow-foreground/10"
            : "border border-border text-foreground/55 hover:border-border hover:text-foreground bg-card/40"
        }`}
    >
      <Icon className={sm ? "w-3 h-3" : "w-3.5 h-3.5"} />
      {label}
    </a>
  );
}

function ProjectsSkeleton() {
  return (
    <div className="space-y-10">
      {/* Featured skeleton */}
      <div className="h-[380px] sm:h-[420px] rounded-[2rem] border border-border bg-card/40 animate-pulse" />
      {/* Tabs skeleton */}
      <div className="flex gap-2">
        {[1, 2, 3].map((i) => (
          <div
            key={i}
            className="h-10 w-28 rounded-xl bg-card/50 animate-pulse"
          />
        ))}
      </div>
      {/* Cards skeleton */}
      <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
        {[1, 2, 3, 4, 5, 6].map((i) => (
          <div
            key={i}
            className="rounded-2xl border border-border bg-card/40 animate-pulse overflow-hidden"
          >
            <div className="aspect-[16/9] bg-card/50" />
            <div className="p-5 space-y-3">
              <div className="h-4 w-3/4 bg-card/60 rounded" />
              <div className="h-3 w-full bg-card/50 rounded" />
              <div className="h-3 w-5/6 bg-card/50 rounded" />
              <div className="flex gap-1.5 pt-1">
                {[1, 2, 3].map((j) => (
                  <div key={j} className="h-6 w-14 rounded-lg bg-card/50" />
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function ProjectCard({ project }: { project: Project }) {
  const badge =
    categoryBadge[project.category] ??
    "bg-white/5 border-white/10 text-foreground/50";
  const accentBar =
    categoryAccentBar[project.category] ?? "from-white/20 to-transparent";

  return (
    <div className="group relative flex flex-col rounded-2xl border border-border bg-card/40 hover:border-white/[0.16] hover:bg-white/[0.035] transition-all duration-300 overflow-hidden">
      {/* Thumbnail */}
      <div className="relative aspect-[16/9] overflow-hidden">
        <img
          src={project.image}
          alt={project.title}
          className="w-full h-full object-cover opacity-55 group-hover:opacity-75 group-hover:scale-[1.04] transition-all duration-700 ease-out"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />

        {/* Overlay badges */}
        <div className="absolute top-3 left-3 right-3 flex items-center justify-between">
          <span
            className={`px-2.5 py-1 text-[9px] font-bold uppercase tracking-widest border rounded-lg backdrop-blur-sm ${badge}`}
          >
            {categoryLabel[project.category] || project.category}
          </span>
          <span className="px-2.5 py-1 text-[9px] font-bold text-foreground/40 bg-background/40 backdrop-blur-sm border border-border rounded-lg">
            {project.year}
          </span>
        </div>

        {/* Hover quick-actions */}
        <div className="absolute inset-0 flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-opacity duration-250">
          <a
            href={project.demoLink}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-1.5 px-4 py-2 bg-white text-black text-xs font-bold rounded-xl shadow-2xl hover:bg-white/90 transition-colors"
          >
            <ExternalLink className="w-3 h-3" /> Live
          </a>
          {project.githubLink && (
            <a
              href={project.githubLink}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1.5 px-4 py-2 bg-background/80 text-foreground text-xs font-bold rounded-xl border border-border backdrop-blur-sm hover:bg-background/60 transition-colors"
            >
              <GitBranch className="w-3 h-3" /> Code
            </a>
          )}
        </div>
      </div>

      {/* Body */}
      <div className="flex flex-col flex-1 p-4 sm:p-5">
        {/* Accent gradient line */}
        <div
          className={`h-px w-full bg-gradient-to-r ${accentBar} mb-4 rounded-full opacity-70`}
        />

        <div className="flex items-start justify-between gap-2 mb-1">
          <h4 className="text-sm sm:text-[15px] font-bold text-foreground/90 leading-snug">
            {project.title}
          </h4>
          <ArrowUpRight className="w-4 h-4 text-foreground/20 group-hover:text-foreground/60 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-all duration-200 shrink-0 mt-0.5" />
        </div>

        <p className="text-[10px] font-bold text-foreground/30 mb-2 uppercase tracking-wider">
          {project.tagline}
          {project.client && ` ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€š· ${project.client}`}
        </p>

        <p className="text-[12px] text-foreground/40 leading-relaxed mb-4 line-clamp-2 flex-1">
          {project.description}
        </p>

        {/* Tech pills */}
        <div className="flex flex-wrap gap-1.5 mb-4">
          {project.tech.slice(0, 3).map((t) => (
            <TechPill key={t} label={t} />
          ))}
          {project.tech.length > 3 && (
            <TechPill label={`+${project.tech.length - 3}`} />
          )}
        </div>

        {/* Actions */}
        <div className="flex gap-2 flex-wrap">
          <ActionBtn
            href={project.demoLink}
            icon={ExternalLink}
            label="Live Demo"
            filled
            sm
          />
          {project.githubLink && (
            <ActionBtn
              href={project.githubLink}
              icon={GitBranch}
              label="Source"
              sm
            />
          )}
        </div>
      </div>
    </div>
  );
}

function FeaturedCard({ project }: { project: Project }) {
  return (
    <div className="relative mb-10 sm:mb-12 rounded-[2rem] overflow-hidden border border-border bg-card/40">
      <div className="absolute inset-0">
        <img
          src={project.image}
          alt={project.title}
          className="w-full h-full object-cover scale-[1.06] opacity-35 blur-[2px]"
        />
        <div className="absolute inset-0 bg-background/60" />
        <div className="absolute inset-0 bg-gradient-to-r from-background/85 via-background/70 to-background/15" />
        <div className="absolute inset-0 bg-gradient-to-t from-background/75 via-transparent to-transparent" />
      </div>
      <div
        className="absolute inset-0 opacity-[0.03]"
        style={{
          backgroundImage:
            "repeating-linear-gradient(0deg,transparent,transparent 39px,rgba(255,255,255,1) 39px,rgba(255,255,255,1) 40px),repeating-linear-gradient(90deg,transparent,transparent 39px,rgba(255,255,255,1) 39px,rgba(255,255,255,1) 40px)",
        }}
      />

      <div className="relative z-10 grid lg:grid-cols-[1fr_1.25fr] gap-10 p-6 sm:p-10 lg:p-14 items-center">
        <div className="max-w-2xl">
          <p className="text-[10px] font-bold uppercase tracking-[0.22em] text-foreground/55 mb-3">
            {categoryLabel[project.category] || project.tagline || "Project"}
          </p>

          <h3 className="text-3xl sm:text-4xl lg:text-5xl xl:text-6xl font-black text-foreground tracking-tight leading-[0.95] mb-4">
            {project.title}
          </h3>

          <div className="flex flex-wrap items-center gap-2 mb-5">
            <span className="px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider bg-card/60 border border-border rounded-lg text-foreground/75 backdrop-blur-sm">
              {project.projectType === "CLIENT" ? "Client Project" : "Personal"}
            </span>
            {project.client && (
              <span className="px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider bg-card/60 border border-white/[0.1] rounded-lg text-foreground/65 backdrop-blur-sm">
                {project.client}
              </span>
            )}
            {project.year && (
              <span className="px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider bg-card/60 border border-white/[0.1] rounded-lg text-foreground/65 backdrop-blur-sm">
                {project.year}
              </span>
            )}
          </div>

          <p className="text-sm sm:text-[15px] text-foreground/55 leading-relaxed mb-7 max-w-xl">
            {project.description}
          </p>

          <div className="flex flex-wrap gap-2 mb-7">
            {project.tech.slice(0, 6).map((t) => (
              <span
                key={t}
                className="px-3 py-1.5 text-[11px] font-semibold uppercase tracking-wider bg-card/60 border border-white/[0.1] rounded-xl text-foreground/55 backdrop-blur-sm"
              >
                {t}
              </span>
            ))}
          </div>

          <div className="flex flex-wrap gap-3">
            <ActionBtn
              href={project.demoLink}
              icon={ExternalLink}
              label="Visit Website"
              filled
            />
            {project.githubLink && (
              <ActionBtn
                href={project.githubLink}
                icon={GitBranch}
                label="Source Code"
              />
            )}
          </div>
        </div>

        <div className="relative lg:justify-self-end w-full">
          <div className="relative aspect-[16/10] sm:aspect-[16/9] rounded-2xl overflow-hidden border border-border bg-card shadow-[0_24px_80px_rgba(0,0,0,0.25)]">
            <img
              src={project.image}
              alt={project.title}
              className="w-full h-full object-contain"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
export default function Projects() {
  const [activeTab, setActiveTab] = useState<"all" | "my" | "client">("all");

  const { data: allProjects = [], isLoading } = useQuery<Project[]>({
    queryKey: ["projects-public"],
    queryFn: async () => {
      const res = await axios.get("/api/projects");
      return res.data;
    },
  });

  const featuredProject = allProjects.find((p) => p.featured) ?? allProjects[0];

  const filteredProjects = allProjects.filter((p) => {
    if (activeTab === "all") return true;
    if (activeTab === "my") return p.projectType === "MY";
    if (activeTab === "client") return p.projectType === "CLIENT";
    return true;
  });

  const tabs: {
    id: "all" | "my" | "client";
    label: string;
    icon: React.ElementType;
    count: number;
  }[] = [
    {
      id: "all",
      label: "All Project",
      icon: Layers,
      count: allProjects.length,
    },
    {
      id: "my",
      label: "Personal",
      icon: User,
      count: allProjects.filter((p) => p.projectType === "MY").length,
    },
    {
      id: "client",
      label: "Client Project",
      icon: Briefcase,
      count: allProjects.filter((p) => p.projectType === "CLIENT").length,
    },
  ];

  return (
    <section id="projects" className="mb-16 sm:mb-20 scroll-mt-24">
      <div className="flex items-end gap-4 sm:gap-6 mb-10 sm:mb-12">
        <div>
          <div className="flex items-center gap-2 mb-3">
            <Code2 className="w-3.5 h-3.5 text-foreground/40" />
            <span className="text-[10px] font-bold uppercase tracking-[0.22em] text-foreground/40">
              Selected Work
            </span>
          </div>
          <h2 className="text-[clamp(28px,5vw,48px)] font-black text-foreground tracking-tight leading-none">
            Projects<span className="text-foreground/25">.</span>
          </h2>
        </div>
        <div className="flex-1 mb-2 hidden sm:block">
          <div className="h-px bg-gradient-to-r from-white/10 to-transparent" />
        </div>
        <span className="text-xs font-mono text-foreground/20 mb-2 hidden sm:block">
          &lt;portfolio /&gt;
        </span>
      </div>

      {isLoading ? (
        <ProjectsSkeleton />
      ) : (
        <>
          {/* Featured hero */}
          {featuredProject && <FeaturedCard project={featuredProject} />}

          {/* Filter tabs + count */}
          <div className="flex items-center justify-between mb-6 sm:mb-8 gap-4 flex-wrap">
            <div className="flex items-center gap-1 p-1 bg-card/40 border border-border rounded-2xl overflow-x-auto">
              {tabs.map(({ id, label, icon: Icon, count }) => (
                <button
                  key={id}
                  onClick={() => setActiveTab(id)}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2.5 rounded-xl text-[11px] font-bold transition-all duration-200 whitespace-nowrap
                    ${
                      activeTab === id
                        ? "bg-white text-black shadow-lg"
                        : "text-foreground/40 hover:text-foreground/65"
                    }`}
                >
                  <Icon className="w-3.5 h-3.5" />
                  <span className="hidden sm:inline">{label}</span>
                  <span className="sm:hidden">
                    {id === "all" ? "All" : id === "my" ? "Personal" : "Client"}
                  </span>
                  <span
                    className={`px-1.5 py-0.5 rounded-md text-[10px] font-bold
                      ${activeTab === id ? "bg-black/10 text-black/55" : "bg-card/60 text-foreground/40"}`}
                  >
                    {count}
                  </span>
                </button>
              ))}
            </div>
            <span className="text-[11px] text-foreground/35 font-medium hidden sm:block">
              {filteredProjects.length} project
              {filteredProjects.length !== 1 ? "s" : ""}
            </span>
          </div>

          {/* Grid */}
          {filteredProjects.length > 0 ? (
            <div className="grid gap-4 sm:gap-5 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
              {filteredProjects.map((project) => (
                <ProjectCard key={project.id} project={project} />
              ))}
            </div>
          ) : (
            <div className="text-center py-20 rounded-2xl border border-dashed border-white/[0.07]">
              <p className="text-xs text-foreground/40 uppercase tracking-[0.2em] font-semibold">
                No projects to display
              </p>
            </div>
          )}
        </>
      )}
    </section>
  );
}
